%%%%%%%%%% Function fFigInfV04.m %%%%%%%%%%% Function Figure Information, ver.4% Kei Nakamura% Created on Monday, April 23rd 2007.% Modified on Tuesday, June 5th 2007.%% function inf = fFigInfV04(anl);% returns a information string for figure%% ver.2: for output information with compression factor% ver.3: add inf for resolution% ver.4: For TREX analysisfunction inf = fFigInfV04(anl);  %function headerinf{1} = strcat('peak energy [MeV]:',num2str(ceil(anl.enrgMev)));inf{2} = strcat('resolution [%,rms]:',num2str(0.1*ceil(10*anl.rsltnPcnt)));inf{3} = strcat('energy spread [%,rms]:',num2str(0.1*ceil(10*anl.sprdPcnt)));inf{4} = strcat('divergence [mrad,rms]:',num2str(0.1*ceil(10*anl.dvrgncMrd)));inf{5} = strcat('charge [pC]:',num2str(ceil(anl.pC)));inf{6} = strcat('total energy [mJ]:',num2str(ceil(anl.mJ)));
